import { CardHeader, Typography } from '@material-ui/core'
import React from 'react'

export default function Card({ subject }) {
  return (
    <div>
        <Typography>
        <Card>
            <CardHeader>{subject.title}</CardHeader>
        </Card>
        </Typography>
    </div>
  )
}
